const items = $input.all();
const results = [];
const now = new Date().toISOString();

for (const item of items) {
  const coins = Array.isArray(item.json) ? item.json : [item.json];
  for (const c of coins) {
    if (!c.id) continue;
    const price = c.current_price || 0;
    const high = c.high_24h || price;
    const low = c.low_24h || price;
    const change24h = c.price_change_percentage_24h || 0;
    const change7d = c.price_change_percentage_7d_in_currency || 0;

    const volatility = price > 0 ? (((high - low) / price) * 100) : 0;
    const range = high - low;
    const pricePosition = range > 0 ? (((price - low) / range) * 100) : 50;

    let signal = 'NEUTRAL';
    if (change24h > 3 && change7d > 0) signal = 'BULLISH';
    else if (change24h < -3 && change7d < 0) signal = 'BEARISH';

    results.push({ json: {
      date: now,
      name: c.name,
      symbol: (c.symbol || '').toUpperCase(),
      price_usd: price,
      market_cap: c.market_cap || 0,
      volume_24h: c.total_volume || 0,
      change_24h_pct: Math.round(change24h * 100) / 100,
      change_7d_pct: Math.round(change7d * 100) / 100,
      volatility_pct: Math.round(volatility * 100) / 100,
      price_position_pct: Math.round(pricePosition * 100) / 100,
      signal: signal
    }});
  }
}
return results;

const movers = $input.all().filter(i => Math.abs(Number(i.json['Change 24h %'])) >= 5);
if (movers.length === 0) return [];

let rows = '';
for (const m of movers) {
  const j = m.json;
  const color = j['Signal'] === 'BULLISH' ? '#16a34a' : (j['Signal'] === 'BEARISH' ? '#dc2626' : '#6b7280');
  rows += `<tr>
    <td style="padding:8px;border-bottom:1px solid #eee;"><strong>${j['Name']}</strong> (${j['Symbol']})</td>
    <td style="padding:8px;border-bottom:1px solid #eee;">$${Number(j['Price (USD)']).toLocaleString()}</td>
    <td style="padding:8px;border-bottom:1px solid #eee;color:${color};">${j['Change 24h %']}%</td>
    <td style="padding:8px;border-bottom:1px solid #eee;">${j['Change 7d %']}%</td>
    <td style="padding:8px;border-bottom:1px solid #eee;color:${color};font-weight:bold;">${j['Signal']}</td>
  </tr>`;
}

const html = `<div style="font-family:Arial,sans-serif;max-width:600px;">
  <h2 style="color:#1a1a2e;">📊 Crypto Market Alert</h2>
  <p>The following ${movers.length} coins moved more than 5% in the last 24 hours:</p>
  <table style="width:100%;border-collapse:collapse;">
    <tr style="background:#1a1a2e;color:#fff;">
      <th style="padding:10px;text-align:left;">Coin</th>
      <th style="padding:10px;text-align:left;">Price</th>
      <th style="padding:10px;text-align:left;">24h</th>
      <th style="padding:10px;text-align:left;">7d</th>
      <th style="padding:10px;text-align:left;">Signal</th>
    </tr>
    ${rows}
  </table>
  <p style="color:#888;font-size:12px;margin-top:20px;">Generated by your Crypto Data Pipeline · ${new Date().toLocaleDateString()}</p>
</div>`;

return [{ json: { email_html: html, mover_count: movers.length } }];
